INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2271, 215486, 12, 2334, '[转贴]一句日本小孩的话，足于震惊每一个中国人！', '我有个同事的姐姐早年嫁给了日本人,现住在广岛,孩子在日本的学校读小学. 
<br>　　有一天,小孩参加完学校的&quot;爱国&quot;活动回到家中,突然狠狠对母亲讲:&quot;我恨死中国人了,我要把他们全杀死!&quot;母亲大惊,忙问怎么回事.小孩讲,中国人很坏,杀了那么多日本人!母亲告诉他中国人没错,是日本人跑到中国去杀中国人的.小孩辨说:&quot;我们一粒子弹只能杀死他们一个人,但他们一颗原子弹要杀死我们几万人!&quot;母亲纠正说,原子弹不是中国人投的,而是美国人干的.小孩反驳道:&quot;那我还是恨中国人,他们很坏,都应该死!&quot;母亲赶忙说:&quot;你不应该这么说,**妈是中国人,你的身上流着一半的中国血!&quot;大家猜猜这个八岁的孩子怎么回答? 他说:&quot;那我晚上睡觉时不要再挂蚊帐,我要让蚊子把我身上的中国血全喝光!&quot; 
<br>　　孩子的母亲后来对自己的妹妹讲,现在她都不敢给自己的孩子讲中国,因为她不知道从自己的孩子口中还会讲出什么话!她常常对未来怀有某种莫名的恐惧. 
<br>　　这是真人真事,这种情节无法编造.之所以写下来就是希望善良的中国人知道,这个曾经给我们带来过灾难的邻邦现在是如何教育他们的后代的.我真诚地希望我们的人民应该怎样审视这个邻居,应该怎样发展自己,强大自己,以免那曾经的苦难再次来过!', '我有个同事的姐姐早年嫁给了日本人,现住在广岛,孩子在日本的学校读小学.

有一天,小孩参加完学校的"爱国"活动回到家中,突然狠狠对母亲讲:"我恨死中国人了,我要把他们全杀死!"母亲大惊,忙问怎么回事.小孩讲,中国人很坏,杀了那么多日本人!母亲告诉他中国人没错,是日本人跑到中国去杀中国人的.小孩辨说:"我们一粒子弹只能杀死他们一个人,但他们一颗原子弹要杀死我们几万人!"母亲纠正说,原子弹不是中国人投的,而是美国人干的.小孩反驳道:"那我还是恨中国人,他们很坏,都应该死!"母亲赶忙说:"你不应该这么说,**妈是中国人,你的身上流着一半的中国血!"大家猜猜这个八岁的孩子怎么回答? 他说:"那我晚上睡觉时不要再挂蚊帐,我要让蚊子把我身上的中国血全喝光!"

孩子的母亲后来对自己的妹妹讲,现在她都不敢给自己的孩子讲中国,因为她不知道从自己的孩子口中还会讲出什么话!她常常对未来怀有某种莫名的恐惧.

这是真人真事,这种情节无法编造.之所以写下来就是希望善良的中国人知道,这个曾经给我们带来过灾难的邻邦现在是如何教育他们的后代的.我真诚地希望我们的人民应该怎样审视这个邻居,应该怎样发展自己,强大自己,以免那曾经的苦难再次来过!', NULL, '2003-10-10 18:16:00', 12, '20031025194841_bbsid_215486_board_12_fcf835a617.html', '20031025194841');
